  ('medical-tech-moex-20708', 'medical-tech', 'medical-tech-moex-093-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '關於甲狀腺癌的敘述，何者錯誤？ 乳突狀癌最多    濾泡狀癌易發生血行性轉移於肺及骨等 前兩者的開刀存活率均高   濾泡狀癌以甲狀腺機能亢進為主徵', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:16+00:00", "source_pdf_sha1": "c666316c921a", "answer_pdf_sha1": "c8ad2e506300", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 47, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20709', 'medical-tech', 'medical-tech-moex-093-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '何種甲狀腺腫瘤是由C細胞變化而成，且常會分泌抑鈣激素（calcitonin）？ 乳頭狀癌（papillary carcinoma）  濾泡性癌（follicular carcinoma） 髓樣細胞癌（medullary carcinoma）  赫索氏細胞腺瘤（Hurthle cell adenoma）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:16+00:00", "source_pdf_sha1": "c666316c921a", "answer_pdf_sha1": "c8ad2e506300", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 48, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20710', 'medical-tech', 'medical-tech-moex-093-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '下列何者為性聯遺傳疾病？ 海洋性貧血  鐮狀細胞貧血  亨丁頓氏病  血友病', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:16+00:00", "source_pdf_sha1": "c666316c921a", "answer_pdf_sha1": "c8ad2e506300", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 49, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20711', 'medical-tech', 'medical-tech-moex-093-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '下列有關帕金森氏病（Parkinson’s disease）的陳述，何者不正確？ 好發於中老年男性    多數病患神志不清、認知功能下降 肌肉僵化、震顫    主要病理變化在黑質核', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:16+00:00", "source_pdf_sha1": "c666316c921a", "answer_pdf_sha1": "c8ad2e506300", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 50, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20712', 'medical-tech', 'medical-tech-moex-093-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '有關嗜鉻細胞瘤（pheochromocytoma）的敘述，何者錯誤？ 可致高血壓  可發生於腎上腺外  源自於腎髓質細胞  多數為惡性', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:16+00:00", "source_pdf_sha1": "c666316c921a", "answer_pdf_sha1": "c8ad2e506300", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 51, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20713', 'medical-tech', 'medical-tech-moex-093-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '下列何種卵巢腫瘤的惡性度最高？ 卵囊膜瘤（thecoma）    卵黃囊腫瘤（yolk-sac tumor） 成熟畸胎瘤（mature teratoma）  黏液性囊腺瘤（mucinous cystadenoma）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:16+00:00", "source_pdf_sha1": "c666316c921a", "answer_pdf_sha1": "c8ad2e506300", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 52, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20714', 'medical-tech', 'medical-tech-moex-093-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '有關子宮肌瘤（leiomyoma）之敘述，何者正確？ 病變源自子宮內膜層    是最常見的子宮腫瘤 主要發生在停經後婦女    有很高的機會轉變為惡性肌肉瘤', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:16+00:00", "source_pdf_sha1": "c666316c921a", "answer_pdf_sha1": "c8ad2e506300", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 53, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20715', 'medical-tech', 'medical-tech-moex-093-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '一名25歲女性因經期疼痛就醫，發現有5公分卵巢囊腫，內有舊血液存在，下列何種情形最可能？ 子宮外孕  子宮內膜異位  卵巢癌  卵巢膿瘍', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:16+00:00", "source_pdf_sha1": "c666316c921a", "answer_pdf_sha1": "c8ad2e506300", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 54, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
